class SecureTaskValidator:
    """Validates task messages to prevent injection attacks"""
    
    ALLOWED_TASK_TYPES = {'process_data', 'send_email', 'generate_report', 'backup_data'}
    MAX_MESSAGE_SIZE = 1024 * 100  # 100KB
    MAX_PRIORITY = 10
    
    @staticmethod
    def validate_task(task_data: Dict[str, Any]) -> bool:
        """Validate task data structure and content"""
        if not isinstance(task_data, dict):
            raise ValueError("Task data must be a dictionary")
        
        # Validate required fields
        if 'task_type' not in task_data:
            raise ValueError("Task must contain 'task_type' field")
        
        # Validate task type against allowlist
        if task_data['task_type'] not in SecureTaskValidator.ALLOWED_TASK_TYPES:
            raise ValueError(f"Invalid task type. Allowed types: {SecureTaskValidator.ALLOWED_TASK_TYPES}")
        
        # Validate message size
        message_size = len(json.dumps(task_data).encode('utf-8'))
        if message_size > SecureTaskValidator.MAX_MESSAGE_SIZE:
            raise ValueError(f"Message size exceeds maximum allowed size of {SecureTaskValidator.MAX_MESSAGE_SIZE} bytes")
        
        # Validate priority if present
        if 'priority' in task_data:
            priority = task_data['priority']
            if not isinstance(priority, int) or not (0 <= priority <= SecureTaskValidator.MAX_PRIORITY):
                raise ValueError(f"Priority must be an integer between 0 and {SecureTaskValidator.MAX_PRIORITY}")
        
        # Sanitize string fields
        for key, value in task_data.items():
            if isinstance(value, str):
                if len(value) > 10000:
                    raise ValueError(f"String field '{key}' exceeds maximum length")
                # Check for potential injection patterns
                if any(char in value for char in ['\x00', '\r\n']):
                    raise ValueError(f"Invalid characters in field '{key}'")
        
        return True


